UPDATE CARD_CATEGORIES
SET    category_name = #{categoryName},
       icon_code     = #{iconCode,     jdbcType=VARCHAR},
       display_order = #{displayOrder, jdbcType=NUMERIC},
       use_yn        = #{useYn}
WHERE  category_id   = #{categoryId}

UPDATE CARD_CATEGORIES
SET    use_yn = 'N'
WHERE  category_id = #{categoryId}
